// Validate webhook token and ensure MR merged into main
const headers = $input.first().json.headers;
const body = $input.first().json.body;

// --- Token validation ---
const receivedToken = headers['x-gitlab-token'] || headers['X-Gitlab-Token'] || '';
const expectedToken = $env.GITLAB_WEBHOOK_SECRET;

if (!receivedToken || receivedToken !== expectedToken) {
  return [{ json: {
    valid: false,
    reason: 'Invalid or missing X-Gitlab-Token'
  }}];
}

// --- Event type ---
const eventType = headers['x-gitlab-event'] || headers['X-Gitlab-Event'] || '';
if (eventType !== 'Merge Request Hook') {
  return [{ json: {
    valid: false,
    reason: `Expected Merge Request Hook, got: ${eventType}`
  }}];
}

// --- MR merged into main ---
const attrs = body.object_attributes || {};
if (attrs.state !== 'merged' || attrs.action !== 'merge') {
  return [{ json: {
    valid: false,
    reason: `MR not merged (state=${attrs.state}, action=${attrs.action})`
  }}];
}

if (attrs.target_branch !== 'main') {
  return [{ json: {
    valid: false,
    reason: `Target branch is '${attrs.target_branch}', not 'main'`
  }}];
}

// --- Extract ---
const project = body.project || {};
const user = body.user || {};
const lastCommit = attrs.last_commit || {};

return [{ json: {
  valid: true,
  project_id: project.id,
  project_name: project.name,
  project_path: project.path_with_namespace,
  project_url: project.web_url,
  commit_sha: attrs.merge_commit_sha || lastCommit.id || 'unknown',
  commit_short: (attrs.merge_commit_sha || lastCommit.id || '').substring(0, 8),
  commit_message: lastCommit.message || attrs.title || '',
  mr_title: attrs.title,
  mr_iid: attrs.iid,
  mr_url: attrs.url,
  source_branch: attrs.source_branch,
  author: user.username || user.name || 'unknown',
  gitlab_api_url: $env.GITLAB_API_URL || 'https://gitlab.com/api/v4',
  timestamp: new Date().toISOString()
}}];

// Calculate CalVer: v{YYYY}.{MM}.{DD}.{N}
const prevData = $('Validate MR to Main').first().json;
const tags = $input.first().json;

const now = new Date();
const yyyy = now.getFullYear();
const mm = String(now.getMonth() + 1).padStart(2, '0');
const dd = String(now.getDate()).padStart(2, '0');
const datePrefix = `v${yyyy}.${mm}.${dd}`;

// Find max N for today
let maxN = 0;
const tagList = Array.isArray(tags) ? tags : [];

for (const tag of tagList) {
  const name = tag.name || '';
  if (name.startsWith(datePrefix + '.')) {
    const nStr = name.replace(datePrefix + '.', '');
    const n = parseInt(nStr, 10);
    if (!isNaN(n) && n > maxN) maxN = n;
  }
}

const nextN = maxN + 1;
const newTag = `${datePrefix}.${nextN}`;

// Find previous tag for changelog range
const previousTag = tagList.length > 0 ? tagList[0].name : null;

return [{ json: {
  ...prevData,
  new_tag: newTag,
  previous_tag: previousTag,
  tag_message: `Release ${newTag}\n\nMR !${prevData.mr_iid}: ${prevData.mr_title}\nBranch: ${prevData.source_branch} -> main\nAuthor: ${prevData.author}`,
  existing_tags_today: tagList.filter(t => (t.name || '').startsWith(datePrefix + '.')).length
}}];

// Prepare data for GitHub tag + GitLab release (run after GitLab tag created)
const data = $('Calculate CalVer').first().json;
const tagResult = $input.first().json;

return [{ json: {
  ...data,
  gitlab_tag_created: !!(tagResult && (tagResult.name || tagResult.tag_name)),
  gitlab_tag_response: tagResult
}}];

// Final webhook response with full tag summary
const data = $('Calculate CalVer').first().json;

return [{ json: {
  status: 'tagged',
  tag: data.new_tag,
  project: data.project_name,
  commit: data.commit_short,
  mr_iid: data.mr_iid,
  gitlab_tag: true,
  gitlab_release: true,
  github_tag: true,
  timestamp: new Date().toISOString()
}}];

// Rejected: invalid token, wrong event, not merged to main
return [{ json: {
  status: 'ignored',
  reason: $json.reason || 'Validation failed',
  timestamp: new Date().toISOString()
}}];
